// Manual trigger config with hardcoded defaults.
// Change outputMode to 'slack' or 'notion' to test other output paths.
//
// Credentials: create in n8n (Credentials > New > HTTP Header Auth):
//   "Anthropic API": header name = x-api-key, value = your Anthropic key
//   "Notion API": header name = Authorization, value = Bearer YOUR_NOTION_KEY

const outputMode = 'markdown';
const daysBack = 30;

const VALID_MODES = ['markdown', 'slack', 'notion'];
if (!VALID_MODES.includes(outputMode)) {
  throw new Error('Invalid outputMode: "' + outputMode + '". Must be one of: ' + VALID_MODES.join(', '));
}

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - daysBack);
const cutoffISO = cutoffDate.toISOString().split('T')[0];

return [{ json: {
  apiKey: 'REPLACE_WITH_ANTHROPIC_API_KEY',
  appId: 'REPLACE_WITH_APP_ID',
  outputMode: outputMode,
  outputPath: 'REPLACE_WITH_YOUR_OUTPUT_PATH',
  slackWebhookUrl: 'REPLACE_WITH_SLACK_WEBHOOK_URL',
  slackBotToken: 'REPLACE_WITH_SLACK_BOT_TOKEN',
  notionDatabaseId: 'REPLACE_WITH_NOTION_DATABASE_ID',
  fileWriterSecret: 'REPLACE_WITH_FILE_WRITER_SECRET',
  channelId: '',
  userId: '',
  userName: '',
  responseUrl: '',
  platformFilter: '',
  daysBack: daysBack,
  cutoffDate: cutoffISO
} }];

const body = $input.first().json.body || $input.first().json;
const text = (body.text || '').trim();
const channelId = body.channel_id || '';
const userId = body.user_id || '';
const userName = body.user_name || '';
const responseUrl = body.response_url || '';

let platformFilter = '';
let daysBack = 30;

const allTime = /\ball\b/i.test(text);
const timeMatch = text.match(/last\s+(\d+)\s+days?/i);

if (allTime) {
  daysBack = 36500;
} else if (timeMatch) {
  daysBack = parseInt(timeMatch[1], 10);
  if (isNaN(daysBack) || daysBack < 1) daysBack = 30;
}

const filterText = text.replace(/last\s+\d+\s+days?/i, '').replace(/\ball\b/i, '').trim();
if (filterText) {
  platformFilter = filterText.toLowerCase();
}

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - daysBack);
const cutoffISO = cutoffDate.toISOString().split('T')[0];

return [{
  json: {
    channelId: channelId,
    userId: userId,
    userName: userName,
    responseUrl: responseUrl,
    platformFilter: platformFilter,
    daysBack: daysBack,
    cutoffDate: cutoffISO,
    rawText: text
  }
}];

const item = $input.first();

// HTTP node may return parsed JSON (item.json.feed) or a string wrapper (item.json.data)
let feed;
if (item.json.feed) {
  feed = item.json.feed;
} else if (item.json.data) {
  try { feed = JSON.parse(item.json.data).feed; } catch(e) { feed = null; }
} else {
  feed = null;
}

const entries = (feed && feed.entry) || [];

// Get config from whichever config node ran (fan-in: only one fires)
const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.cutoffDate) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});
const cutoff = config.cutoffDate || '';
const platformFilter = config.platformFilter || '';

const reviews = entries
  .filter(function(entry) {
    return entry['im:rating'] !== undefined;
  })
  .map(function(entry) {
    const rawDate = (entry.updated && entry.updated.label) || '';
    return {
      json: {
        text: ((entry.content && entry.content.label) || (entry.title && entry.title.label) || '').slice(0, 500),
        source: 'App Store',
        date: rawDate ? rawDate.split('T')[0] : '',
        rating: (entry['im:rating'] && entry['im:rating'].label) || ''
      }
    };
  })
  .filter(function(item) { return item.json.text.trim() !== ''; })
  .filter(function(item) {
    if (cutoff && item.json.date) {
      return item.json.date >= cutoff;
    }
    return true;
  })
  .filter(function(item) {
    if (platformFilter) {
      return item.json.text.toLowerCase().indexOf(platformFilter) !== -1 ||
             item.json.source.toLowerCase().indexOf(platformFilter) !== -1;
    }
    return true;
  });

return reviews.length > 0 ? reviews : [{ json: { text: '', source: 'App Store', date: '', rating: '' } }];

const items = $input.all();
const feedbackItems = items
  .map(function(item) {
    return {
      text: (item.json.text || item.json.Text || '').toString().trim(),
      source: (item.json.source || item.json.Source || 'Unknown').toString().trim(),
      date: (item.json.date || item.json.Date || '').toString().trim()
    };
  })
  .filter(function(item) { return item.text !== ''; })
  .map(function(item) {
    // Sanitize text: replace curly quotes, smart apostrophes, and other unicode chars that break JSON
    item.text = item.text
      .replace(/[\u2018\u2019\u201A]/g, "'")
      .replace(/[\u201C\u201D\u201E]/g, '"')
      .replace(/[\u2026]/g, '...')
      .replace(/[\u2013]/g, '-')
      .replace(/[\u2014]/g, '-')
      .replace(/[^\x20-\x7E\n]/g, '');
    return item;
  })
  .map(function(item) { item.text = item.text.slice(0, 1000); return item; });

if (feedbackItems.length === 0) {
  // Return empty signal so downstream IF node can route to "no data" path
  return [{
    json: {
      total_items: 0,
      source_count: 0,
      empty: true,
      body: ''
    }
  }];
}

const sources = feedbackItems.map(function(i) { return i.source; });
const uniqueSources = sources.filter(function(v, i) { return sources.indexOf(v) === i; });

const system = 'You are a product manager synthesizing user research. Group customer feedback into named themes.';
const user = 'Cluster these feedback items into 5-10 themes. Return a JSON array ONLY with no markdown and no explanation. Each element: theme_id (integer), theme_name (3-6 word noun phrase), items (array with text and source fields). Start with [ and end with ].\n\nFeedback:\n' + JSON.stringify(feedbackItems);

return [{
  json: {
    total_items: feedbackItems.length,
    source_count: uniqueSources.length,
    empty: false,
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

// Only relevant when triggered via Slack. For manual trigger, this path just ends.
const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.channelId) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});

const filter = config.platformFilter || '';
const days = config.daysBack || 30;
const channelId = config.channelId || '';
const slackBotToken = config.slackBotToken || '';

if (!channelId) {
  // Manual trigger with no Slack context, nothing to post
  return [{ json: { skip: true } }];
}

let msg = 'No feedback items found';
if (filter) msg += ' matching "' + filter + '"';
msg += ' in the last ' + days + ' days.';
msg += ' Try a broader search or a longer time range.';

return [{
  json: {
    channelId: channelId,
    slackBotToken: slackBotToken,
    slackBody: JSON.stringify({
      channel: channelId,
      text: msg
    })
  }
}];

const item = $input.first();
if (item.json.error) {
  throw new Error('Claude API error: ' + (item.json.error.message || JSON.stringify(item.json.error)));
}
if (!item.json.content || !item.json.content[0]) {
  throw new Error('Unexpected response from Claude: ' + JSON.stringify(item.json).slice(0, 200));
}
let text = item.json.content[0].text.trim();

if (text.charAt(0) !== '[') {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start !== -1 && end !== -1) {
    text = text.slice(start, end + 1);
  }
}
let clusters;
try {
  clusters = JSON.parse(text);
} catch (e) {
  throw new Error('Failed to parse Claude clustering response: ' + e.message + ' | Raw: ' + text.slice(0, 300));
}

const system = 'You are a product manager prioritizing a backlog using a RICE-adjacent scoring framework.';
const user = 'Score each of these feedback theme clusters on 4 dimensions (1-10 each):\n- frequency: relative cluster size vs others (10 = most mentions)\n- sentiment: emotional charge and urgency (10 = highest)\n- revenue_signal: connection to churn, enterprise accounts, or upgrade blockers (10 = strongest)\n- effort_hint: apparent implementation complexity (10 = simplest to build)\n\nComposite score: Math.round((frequency*2 + sentiment*2 + revenue_signal*3 + effort_hint*1) / 8 * 10)\n\nReturn JSON array ONLY, no markdown, no explanation. Each element: theme_id, theme_name, item_count, frequency_score, sentiment_score, revenue_signal_score, effort_hint_score, composite_score, scoring_rationale (2 sentences). Start with [ end with ].\n\nClusters:\n' + JSON.stringify(clusters);

return [{
  json: {
    total_items: $node['Code - Normalize'].json.total_items,
    source_count: $node['Code - Normalize'].json.source_count,
    clusters: clusters,
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 2048,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const item = $input.first();
if (item.json.error) {
  throw new Error('Claude API error: ' + (item.json.error.message || JSON.stringify(item.json.error)));
}
if (!item.json.content || !item.json.content[0]) {
  throw new Error('Unexpected response from Claude: ' + JSON.stringify(item.json).slice(0, 200));
}
let text = item.json.content[0].text.trim();

if (text.charAt(0) !== '[') {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start !== -1 && end !== -1) {
    text = text.slice(start, end + 1);
  }
}
let scores;
try {
  scores = JSON.parse(text);
} catch (e) {
  throw new Error('Failed to parse Claude scoring response: ' + e.message + ' | Raw: ' + text.slice(0, 300));
}
scores.sort(function(a, b) { return b.composite_score - a.composite_score; });

const clusters = $node['Code - Parse Clusters'].json.clusters;
const today = new Date().toISOString().split('T')[0];
const totalItems = $node['Code - Normalize'].json.total_items;
const sourceCount = $node['Code - Normalize'].json.source_count;

// Resolve config from whichever trigger path ran
const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.outputPath) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});
const outputPath = config.outputPath || '';

const header = '# Feature Request Intelligence Report\n**Generated:** ' + today + '\n**Sources:** ' + totalItems + ' items across ' + sourceCount + ' sources\n**Themes identified:** ' + scores.length;

const system = 'You are a senior product manager writing an intelligence report. Be direct, specific, and strategic. Write for time-constrained PMs and stakeholders.';
const user = 'Write a Markdown feature request intelligence report. Start with this exact header block (copy verbatim):\n\n' + header + '\n\nThen include:\n1. ## Executive Summary (2-3 sentences on what customers want most and why it matters now)\n2. ## Prioritized Themes, one ### subsection per theme with: score, frequency, sentiment, revenue signal, 2 representative quotes from the cluster items, 1-sentence recommendation\n3. ## Recommended Next Actions (3 concrete bullets)\n\nScored themes (sorted by priority):\n' + JSON.stringify(scores) + '\n\nOriginal clusters with full quote list:\n' + JSON.stringify(clusters);

return [{
  json: {
    filename: outputPath + '/' + today + '-feature-request-report.md',
    scores: scores,
    total_items: totalItems,
    source_count: sourceCount,
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const item = $input.first();
if (item.json.error) {
  throw new Error('Claude API error: ' + (item.json.error.message || JSON.stringify(item.json.error)));
}
if (!item.json.content || !item.json.content[0]) {
  throw new Error('Unexpected response from Claude: ' + JSON.stringify(item.json).slice(0, 200));
}
const reportContent = item.json.content[0].text;
const parsed = $node['Code - Parse Scores'].json;

return [{
  json: {
    filename: parsed.filename,
    report: reportContent,
    scores: parsed.scores,
    total_items: parsed.total_items,
    source_count: parsed.source_count,
    body: JSON.stringify({
      filename: parsed.filename,
      content: reportContent
    })
  }
}];

const item = $input.first();
const report = item.json.report;
const scores = item.json.scores || [];
const today = new Date().toISOString().split('T')[0];
const totalItems = item.json.total_items;
const sourceCount = item.json.source_count;

// Resolve config from whichever trigger path ran
const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.channelId) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});
const channelId = config.channelId || '';
const userId = config.userId || '';
const platformFilter = config.platformFilter || '';
const daysBack = config.daysBack || 30;
const slackBotToken = config.slackBotToken || '';

// Extract executive summary from the markdown report
const execMatch = report.match(/## Executive Summary\n([\s\S]*?)(?=\n## )/);
const execSummary = execMatch ? execMatch[1].trim().replace(/\n+/g, ' ').slice(0, 400) : '';

const filterNote = platformFilter ? ' | Filter: "' + platformFilter + '"' : '';
const userMention = userId ? 'Requested by <@' + userId + '> | ' : '';

const blocks = [
  {
    "type": "header",
    "text": {"type": "plain_text", "text": "Feature Request Intelligence, " + today}
  },
  {
    "type": "context",
    "elements": [
      {"type": "mrkdwn", "text": userMention + "Last " + daysBack + " days" + filterNote}
    ]
  },
  {
    "type": "section",
    "fields": [
      {"type": "mrkdwn", "text": "*Items analyzed:* " + totalItems},
      {"type": "mrkdwn", "text": "*Sources:* " + sourceCount},
      {"type": "mrkdwn", "text": "*Themes found:* " + scores.length}
    ]
  }
];

if (execSummary) {
  blocks.push({"type": "section", "text": {"type": "mrkdwn", "text": execSummary}});
}

blocks.push({"type": "divider"});
blocks.push({"type": "section", "text": {"type": "mrkdwn", "text": "*Top Priority Themes:*"}});

scores.slice(0, 5).forEach(function(theme, i) {
  blocks.push({
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": "*" + (i + 1) + ". " + theme.theme_name + "*, Score: " + theme.composite_score + "/100\n" + (theme.scoring_rationale || '')
    }
  });
});

if (scores.length > 5) {
  blocks.push({
    "type": "context",
    "elements": [{"type": "mrkdwn", "text": "_" + (scores.length - 5) + " more themes in full report_"}]
  });
}

return [{
  json: {
    channelId: channelId,
    slackBotToken: slackBotToken,
    filename: item.json.filename,
    slackBody: JSON.stringify({
      channel: channelId,
      text: "Feature Request Intelligence Report, " + today,
      blocks: blocks,
      unfurl_links: false
    }),
    fileWriterBody: item.json.body
  }
}];

const report = $node['Code - Format Output'].json.report;
const today = new Date().toISOString().split('T')[0];
const filename = today + '-feature-request-report.md';
const fileSize = new TextEncoder().encode(report).length;

const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.channelId) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});

return [{ json: { filename, fileSize, report, channelId: config.channelId || '', slackBotToken: config.slackBotToken || '' } }];

const urlResp = $input.first().json;
const prep = $node['Code - Prep File Upload'].json;
let uploadUrl = urlResp.upload_url;
let fileId = urlResp.file_id;
if (!uploadUrl && urlResp.data) {
  try {
    const parsed = typeof urlResp.data === 'string' ? JSON.parse(urlResp.data) : urlResp.data;
    uploadUrl = parsed.upload_url;
    fileId = parsed.file_id;
  } catch(e) {}
}
return [{ json: { uploadUrl, fileId, report: prep.report, channelId: prep.channelId, slackBotToken: prep.slackBotToken } }];

const item = $input.first();
const report = item.json.report;
const today = new Date().toISOString().split('T')[0];

const configManual = $node['Config (Manual)'];
const configSlack = $node['Config (Slack)'];
const config = (configSlack && configSlack.json && configSlack.json.notionDatabaseId) ? configSlack.json : (configManual && configManual.json ? configManual.json : {});
const dbId = config.notionDatabaseId || '';

// Notion rich_text blocks have a 2000 char limit: chunk the report
const CHUNK = 1900;
const chunks = [];
for (let i = 0; i < report.length; i += CHUNK) {
  chunks.push(report.slice(i, i + CHUNK));
}

const children = chunks.map(function(chunk) {
  return {
    "object": "block",
    "type": "paragraph",
    "paragraph": {
      "rich_text": [{"type": "text", "text": {"content": chunk}}]
    }
  };
});

return [{
  json: {
    body: JSON.stringify({
      "parent": {"database_id": dbId},
      "properties": {
        "Name": {
          "title": [{"text": {"content": "Feature Request Report, " + today}}]
        }
      },
      "children": children
    })
  }
}];
